;(function(){
  if(typeof window==="undefined"||window.__pp_disp_initialized)return;
  window.__pp_disp_initialized=true;

  function escapeHtml(s){
    if(s==null)return"";
    return String(s).replace(/[&<>"']/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c];});
  }
  function fmtFecha(s){
    if(!s)return"—";
    try{
      var d=new Date(s+(s.length===10?"T00:00:00":""));
      if(isNaN(d.getTime()))return s;
      return d.toLocaleDateString("es-HN",{day:"2-digit",month:"2-digit",year:"numeric"});
    }catch(e){return s;}
  }

  // ==== MODAL VER HERRAJES ====
  function ensureModal(){
    var m=document.getElementById("__pp_disp_modal");
    if(m)return m;
    m=document.createElement("div");
    m.id="__pp_disp_modal";
    m.style.cssText="display:none;position:fixed;inset:0;z-index:99998;background:rgba(0,0,0,0.5);align-items:center;justify-content:center;padding:20px;";
    m.innerHTML='<div id="__pp_disp_modal_card" style="background:#fff;border-radius:12px;max-width:560px;width:100%;max-height:80vh;overflow-y:auto;box-shadow:0 20px 50px rgba(0,0,0,.3);"><div id="__pp_disp_modal_head" style="padding:18px 22px;border-bottom:1px solid #e7e5e4;display:flex;justify-content:space-between;align-items:center;gap:12px;"><div id="__pp_disp_modal_title" style="font-size:15px;font-weight:700;color:#0d9488;"></div><button id="__pp_disp_modal_close" style="background:transparent;border:none;color:#78716c;cursor:pointer;font-size:22px;line-height:1;padding:0 4px;">×</button></div><div id="__pp_disp_modal_body" style="padding:18px 22px;font-size:13px;color:#1c1917;"></div></div>';
    document.body.appendChild(m);
    document.getElementById("__pp_disp_modal_close").onclick=function(){m.style.display="none";};
    m.onclick=function(ev){if(ev.target===m)m.style.display="none";};
    return m;
  }

  window.__pp_disp_verHerrajes=function(realIdx){
    var arr=window.__pp_disp_arr||[];
    var d=arr[realIdx];
    if(!d){console.warn("__pp_disp_verHerrajes: no data at idx",realIdx);return;}
    var modal=ensureModal();
    var hData=d.herrajes||{};
    var usados=[];
    var inv=window.__pp_disp_inv||{};
    var productos=(inv.productos||[]);
    Object.keys(hData).forEach(function(k){
      var qty=parseFloat(hData[k])||0;
      if(qty>0){
        var prod=productos.find(function(p){return p.id===k;});
        var label=prod?(prod.codigo||"")+" · "+(prod.descripcion||""):k;
        usados.push({id:k,qty:qty,label:label,unit:prod?(prod.unidadBase||"u"):""});
      }
    });

    var hasPend=d.herrPendDesc&&String(d.herrPendDesc).trim()!==""&&!d.herrPendEntregado;
    var html="";

    if(hasPend){
      html+='<div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:12px;margin-bottom:14px;"><div style="color:#9a3412;font-size:12px;font-weight:700;letter-spacing:0.5px;margin-bottom:6px;">⏳ HERRAJES PENDIENTES POR ENTREGAR</div><div style="color:#7c2d12;font-size:13px;line-height:1.5;white-space:pre-wrap;">'+escapeHtml(d.herrPendDesc)+'</div></div>';
    }

    if(usados.length===0){
      html+='<div style="text-align:center;padding:30px;color:#78716c;font-size:12px;">Sin herrajes registrados en este despacho.</div>';
    }else{
      html+='<div style="font-size:10px;color:#78716c;letter-spacing:1px;font-weight:700;margin-bottom:8px;">'+(hasPend?"HERRAJES REGISTRADOS EN EL DESPACHO":"HERRAJES DESPACHADOS")+'</div>';
      html+='<div style="display:flex;flex-direction:column;gap:6px;">';
      usados.forEach(function(u){
        html+='<div style="display:flex;justify-content:space-between;padding:8px 12px;background:#f5f5f4;border-radius:6px;align-items:center;gap:10px;"><span style="font-weight:500;color:#1c1917;font-size:12px;flex:1;min-width:0;">'+escapeHtml(u.label)+'</span><span style="font-weight:700;color:#0d9488;font-size:13px;white-space:nowrap;">'+u.qty+(u.unit?" "+escapeHtml(u.unit):"")+'</span></div>';
      });
      html+='</div>';
      if(d._movIds&&d._movIds.length>0){
        html+='<div style="margin-top:10px;font-size:10px;color:#0f766e;background:#ecfdf5;padding:6px 10px;border-radius:6px;">✓ Movimientos de inventario asociados: '+d._movIds.length+'</div>';
      }
    }

    document.getElementById("__pp_disp_modal_title").textContent="🔩 "+(d.cliente||"—")+" — "+(d.area||"—")+" ("+fmtFecha(d.fecha)+")";
    document.getElementById("__pp_disp_modal_body").innerHTML=html;
    modal.style.display="flex";
  };

  // ==== MENÚ CONTEXTUAL ====
  var _ctxIdx=null;
  function ensureCtxMenu(){
    var m=document.getElementById("__pp_disp_ctxmenu");
    if(m)return m;
    m=document.createElement("div");
    m.id="__pp_disp_ctxmenu";
    m.style.cssText="display:none;position:fixed;z-index:99999;background:#fff;border:1px solid #e7e5e4;border-radius:10px;padding:6px;min-width:180px;box-shadow:0 8px 24px rgba(0,0,0,.18);font-family:inherit;font-size:12px;";
    m.innerHTML='<div id="__pp_disp_ctxmenu_label" style="color:#78716c;font-size:9px;letter-spacing:1.2px;padding:6px 10px 4px;text-transform:uppercase;border-bottom:1px solid #f5f5f4;margin-bottom:4px;font-weight:700;">DESPACHO</div><button id="__pp_disp_ctxmenu_edit" style="display:flex;align-items:center;gap:8px;width:100%;background:transparent;border:none;color:#0d9488;cursor:pointer;padding:9px 12px;border-radius:6px;font-size:12px;font-weight:600;text-align:left;">✏️ Editar despacho</button><button id="__pp_disp_ctxmenu_del" style="display:flex;align-items:center;gap:8px;width:100%;background:transparent;border:none;color:#dc2626;cursor:pointer;padding:9px 12px;border-radius:6px;font-size:12px;font-weight:600;text-align:left;">🗑 Eliminar despacho</button>';
    document.body.appendChild(m);
    var hover=function(b,c){b.onmouseenter=function(){b.style.background=c;};b.onmouseleave=function(){b.style.background="transparent";};};
    hover(document.getElementById("__pp_disp_ctxmenu_edit"),"#ecfdf5");
    hover(document.getElementById("__pp_disp_ctxmenu_del"),"#fef2f2");
    document.getElementById("__pp_disp_ctxmenu_edit").onclick=function(){_ctxAction("edit");};
    document.getElementById("__pp_disp_ctxmenu_del").onclick=function(){_ctxAction("delete");};
    document.addEventListener("click",function(ev){
      if(!m.contains(ev.target))m.style.display="none";
    });
    document.addEventListener("scroll",function(){m.style.display="none";},true);
    document.addEventListener("keydown",function(ev){if(ev.key==="Escape")m.style.display="none";});
    return m;
  }
  function _ctxAction(action){
    var m=document.getElementById("__pp_disp_ctxmenu");
    if(m)m.style.display="none";
    if(_ctxIdx==null)return;
    var arr=window.__pp_disp_arr||[];
    var d=arr[_ctxIdx];
    if(!d){console.warn("__pp_disp ctxAction: no data");_ctxIdx=null;return;}
    if(action==="edit"&&typeof window.__pp_disp_setW==="function"){
      window.__pp_disp_setW(Object.assign({},d,{__idx:_ctxIdx}));
    }else if(action==="delete"&&typeof window.__pp_disp_setD==="function"){
      window.__pp_disp_setD(_ctxIdx);
    }
    _ctxIdx=null;
  }
  window.__pp_disp_showCtxMenu=function(ev,realIdx){
    _ctxIdx=realIdx;
    var arr=window.__pp_disp_arr||[];
    var d=arr[realIdx];
    var menu=ensureCtxMenu();
    var lbl=document.getElementById("__pp_disp_ctxmenu_label");
    if(lbl&&d)lbl.textContent=(d.cliente||"DESPACHO").slice(0,28);
    menu.style.display="block";
    var vw=window.innerWidth,vh=window.innerHeight;
    var mw=menu.offsetWidth||190,mh=menu.offsetHeight||110;
    var x=ev.clientX+6,y=ev.clientY+6;
    if(x+mw>vw-8)x=ev.clientX-mw-6;
    if(y+mh>vh-8)y=ev.clientY-mh-6;
    if(x<8)x=8;if(y<8)y=8;
    menu.style.left=x+"px";
    menu.style.top=y+"px";
  };

})();
